from fastapi import FastAPI, Depends
from pydantic import BaseModel
import yt_dlp
from transformers import AutoModelForSpeechSeq2Seq, AutoProcessor, pipeline, AutoTokenizer, AutoModelForSeq2SeqLM
import torch
from db import get_db
from sqlalchemy.orm import Session
from model.video import Video
from model.transcribe import Transcribe
import json
from openai import OpenAI
from langchain_text_splitters import RecursiveCharacterTextSplitter
from tqdm import tqdm

app = FastAPI()

device="cuda"
torch_dtype=torch.float16

model_id = "openai/whisper-medium"
model = AutoModelForSpeechSeq2Seq.from_pretrained(
    model_id, torch_dtype=torch_dtype, low_cpu_mem_usage=True, use_safetensors=True
)
model.to(device)

processor = AutoProcessor.from_pretrained(model_id)

pipe = pipeline(
    "automatic-speech-recognition",
    model=model,
    tokenizer=processor.tokenizer,
    feature_extractor=processor.feature_extractor,
    torch_dtype=torch_dtype,
    device=device,
)

class YoutubeRequest(BaseModel):
    url: str

@app.post("/download")
def download_audio(request: YoutubeRequest):

    ydl_opts = {
        "format": "bestaudio/best",
        "outtmpl": "downloads/%(id)s.%(ext)s"
    }

    with yt_dlp.YoutubeDL(ydl_opts) as ydl:
        ydl.download([request.url])

    return {
        "success": True
    }

@app.get("/transcribe")
def transcribe(db: Session = Depends(get_db)):
    try:
        result = pipe('downloads/bX_xY8YvHEw.webm',return_timestamps=True)
        
        return {
            "message": result
        }
        
        
    except Exception as e:
        import traceback
        traceback.print_exc()
        return {
            "error": str(e)
        }

